### Event date range start

Pattern for the start date of an event range (pairs with DateRangePicker):

```jsx live-dev
const App = () => {
  const [startDate, setStartDate] = useState(new CalendarDate(2025, 12, 10));
  const [endDate, setEndDate] = useState(new CalendarDate(2025, 12, 15));
  const today = new CalendarDate(2025, 12, 2);

  const isInvalid = startDate && endDate && startDate.compare(endDate) > 0;

  return (
    <Stack direction="column" gap="400">
      <FormField.Root isInvalid={isInvalid}>
        <FormField.Label>Event Start Date</FormField.Label>
        <FormField.Input>
          <DateInput
            value={startDate}
            onChange={setStartDate}
            minValue={today}
            maxValue={endDate}
            leadingElement={<Icons.Event />}
            aria-label="Event start date"
          />
        </FormField.Input>
        {isInvalid && (
          <FormField.Error>
            Start date must be before end date
          </FormField.Error>
        )}
      </FormField.Root>

      <FormField.Root>
        <FormField.Label>Event End Date</FormField.Label>
        <FormField.Input>
          <DateInput
            value={endDate}
            onChange={setEndDate}
            minValue={startDate || today}
            leadingElement={<Icons.Event />}
            aria-label="Event end date"
          />
        </FormField.Input>
      </FormField.Root>

      <Text fontSize="sm">
        Event duration: {startDate && endDate ? 
          `${endDate.compare(startDate) + 1} day(s)` : 
          'Select dates'}
      </Text>
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using DateInput within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the DateInput renders with expected elements and date segments

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { DateInput, NimbusProvider } from "@commercetools/nimbus";
import { CalendarDate, CalendarDateTime } from "@internationalized/date";

describe("DateInput - Basic rendering", () => {
  it("renders date input with segments", () => {
    render(
      <NimbusProvider>
        <DateInput aria-label="Enter a date" />
      </NimbusProvider>
    );

    // DateInput uses role="group" for the overall field
    expect(screen.getByRole("group")).toBeInTheDocument();
  });

  it("renders with default value", () => {
    const defaultDate = new CalendarDate(2025, 6, 15);

    render(
      <NimbusProvider>
        <DateInput
          defaultValue={defaultDate}
          aria-label="Date with default value"
        />
      </NimbusProvider>
    );

    // Verify segments contain the default values
    expect(screen.getByRole("group")).toBeInTheDocument();
    // Find month value
    expect(screen.getByText("6")).toBeInTheDocument();
  });

  it("renders with leading element", () => {
    render(
      <NimbusProvider>
        <DateInput
          leadingElement={<span data-testid="leading-icon">📅</span>}
          aria-label="Date with icon"
        />
      </NimbusProvider>
    );

    expect(screen.getByTestId("leading-icon")).toBeInTheDocument();
  });

  it("renders with trailing element", () => {
    render(
      <NimbusProvider>
        <DateInput
          trailingElement={<span data-testid="trailing-icon">✕</span>}
          aria-label="Date with trailing icon"
        />
      </NimbusProvider>
    );

    expect(screen.getByTestId("trailing-icon")).toBeInTheDocument();
  });
});
```

### Interaction Tests

Test user interactions with date segments and keyboard navigation

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { DateInput, NimbusProvider } from "@commercetools/nimbus";
import { CalendarDate, CalendarDateTime } from "@internationalized/date";

describe("DateInput - Interactions", () => {
  it("calls onChange when date value changes", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <DateInput
          onChange={handleChange}
          defaultValue={new CalendarDate(2025, 1, 15)}
          aria-label="Interactive date input"
        />
      </NimbusProvider>
    );

    const group = screen.getByRole("group");
    const segments = group.querySelectorAll('[role="spinbutton"]');

    // Focus first segment (month) and use arrow up to increment
    if (segments[0]) {
      await user.click(segments[0]);
      await user.keyboard("{ArrowUp}");

      // onChange should be called with a DateValue (month changed from 1 to 2)
      await waitFor(() => {
        expect(handleChange).toHaveBeenCalled();
        const newValue = handleChange.mock.calls[0][0];
        expect(newValue).toBeInstanceOf(CalendarDate);
      });
    }
  });

  it("allows keyboard navigation between segments", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <DateInput
          defaultValue={new CalendarDate(2025, 6, 15)}
          aria-label="Date for keyboard navigation"
        />
      </NimbusProvider>
    );

    const group = screen.getByRole("group");
    const segments = group.querySelectorAll('[role="spinbutton"]');

    // Focus first segment
    if (segments[0]) {
      await user.click(segments[0]);
      expect(segments[0]).toHaveFocus();

      // Tab to next segment
      await user.keyboard("{Tab}");
      expect(segments[1]).toHaveFocus();
    }
  });

  it("increments segment value with arrow up", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <DateInput
          defaultValue={new CalendarDate(2025, 6, 15)}
          onChange={handleChange}
          aria-label="Date for arrow key test"
        />
